+using System.Collections.Generic;
+using System.Linq;
+using Microsoft.VisualStudio.TestTools.UnitTesting;
+
+namespace ContosoUniversity.Tests
+{
+    [TestClass]
+    public class PaginatedListTests
+    {
+        [TestMethod]
+        public void Constructor_SetsPageIndexAndTotalPages()
+        {
+            var items = new List<int> { 1, 2, 3 };
+            var list = new PaginatedList<int>(items, 10, 2, 3);
+
+            Assert.AreEqual(2, list.PageIndex);
+            Assert.AreEqual(4, list.TotalPages); // ceil(10/3) = 4
+        }
+
+        [TestMethod]
+        public void Constructor_AddsItemsToList()
+        {
+            var items = new List<string> { "a", "b" };
+            var list = new PaginatedList<string>(items, 5, 1, 2);
+
+            Assert.AreEqual(2, list.Count);
+            Assert.AreEqual("a", list[0]);
+            Assert.AreEqual("b", list[1]);
+        }
+
+        [TestMethod]
+        [DataRow(1, false)]  // first page: no previous
+        [DataRow(2, true)]   // second page: has previous
+        [DataRow(3, true)]   // third page: has previous
+        public void HasPreviousPage_ReturnsCorrectValue(int pageIndex, bool expected)
+        {
+            var list = new PaginatedList<int>(new List<int>(), 30, pageIndex, 10);
+            Assert.AreEqual(expected, list.HasPreviousPage);
+        }
+
+        [TestMethod]
+        [DataRow(1, 3, true)]   // page 1 of 3: has next
+        [DataRow(2, 3, true)]   // page 2 of 3: has next
+        [DataRow(3, 3, false)]  // last page: no next
+        public void HasNextPage_ReturnsCorrectValue(int pageIndex, int totalPages, bool expected)
+        {
+            var list = new PaginatedList<int>(new List<int>(), totalPages * 10, pageIndex, 10);
+            Assert.AreEqual(expected, list.HasNextPage);
+        }
+
+        [TestMethod]
+        [DataRow(10, 3, 4)]  // ceil(10/3) = 4
+        [DataRow(9, 3, 3)]   // exact division
+        [DataRow(1, 10, 1)]  // one item
+        [DataRow(0, 10, 0)]  // no items
+        public void TotalPages_CalculatedCorrectly(int count, int pageSize, int expectedTotalPages)
+        {
+            var list = new PaginatedList<int>(new List<int>(), count, 1, pageSize);
+            Assert.AreEqual(expectedTotalPages, list.TotalPages);
+        }
+
+        [TestMethod]
+        public void Create_ReturnsCorrectPage()
+        {
+            var source = Enumerable.Range(1, 25).AsQueryable();
+
+            var result = PaginatedList<int>.Create(source, 2, 10);
+
+            Assert.AreEqual(2, result.PageIndex);
+            Assert.AreEqual(3, result.TotalPages); // ceil(25/10) = 3
+            Assert.AreEqual(10, result.Count);
+            Assert.AreEqual(11, result[0]); // second page starts at 11
+        }
+
+        [TestMethod]
+        public void Create_FirstPage_ReturnsFirstItems()
+        {
+            var source = Enumerable.Range(1, 5).AsQueryable();
+
+            var result = PaginatedList<int>.Create(source, 1, 3);
+
+            Assert.AreEqual(3, result.Count);
+            Assert.AreEqual(1, result[0]);
+            Assert.AreEqual(3, result[2]);
+        }
+
+        [TestMethod]
+        public void Create_LastPage_ReturnsRemainingItems()
+        {
+            var source = Enumerable.Range(1, 7).AsQueryable();
+
+            var result = PaginatedList<int>.Create(source, 3, 3);
+
+            Assert.AreEqual(1, result.Count);
+            Assert.AreEqual(7, result[0]);
+        }
+
+        [TestMethod]
+        public void Create_EmptySource_ReturnsEmptyList()
+        {
+            var source = new List<int>().AsQueryable();
+
+            var result = PaginatedList<int>.Create(source, 1, 10);
+
+            Assert.AreEqual(0, result.Count);
+            Assert.AreEqual(0, result.TotalPages);
+            Assert.IsFalse(result.HasPreviousPage);
+            Assert.IsFalse(result.HasNextPage);
+        }
+
+        [TestMethod]
+        public void Create_SinglePage_NoNavigationNeeded()
+        {
+            var source = Enumerable.Range(1, 5).AsQueryable();
+
+            var result = PaginatedList<int>.Create(source, 1, 10);
+
+            Assert.AreEqual(5, result.Count);
+            Assert.AreEqual(1, result.TotalPages);
+            Assert.IsFalse(result.HasPreviousPage);
+            Assert.IsFalse(result.HasNextPage);
+        }
+    }
+}
