    {
        private SchoolContext GetDbContext(string dbName = null)
        {
            dbName ??= Guid.NewGuid().ToString();
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(databaseName: dbName)
                .Options;
            return new SchoolContext(options);
        }

        private CoursesController CreateController(SchoolContext context, string webRootPath = null)
        {
            var envMock = new Mock<IWebHostEnvironment>();
            envMock.Setup(e => e.WebRootPath).Returns(webRootPath);
            envMock.Setup(e => e.ContentRootPath).Returns(webRootPath ?? "/fakepath");
            var loggerMock = new Mock<ILogger<CoursesController>>();
            return new CoursesController(context, envMock.Object, loggerMock.Object);
        }

        private void SeedDepartment(SchoolContext context)
        {
            if (!context.Departments.Any())
            {
                context.Departments.Add(new Department
                {
                    Name = "Engineering",
                    Budget = 100000m,
                    StartDate = new DateTime(2020, 9, 1)
                });
                context.SaveChanges();
            }
        }

        private Course SeedCourse(SchoolContext context, int courseId = 1050)
        {
            SeedDepartment(context);
            var dept = context.Departments.First();
            var course = new Course
            {
                CourseID = courseId,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = dept.DepartmentID
            };
            context.Courses.Add(course);
            context.SaveChanges();
            return course;
        }

