        [DataRow(".gif")]
        [DataRow(".bmp")]
        public void CreatePost_ValidFileExtension_Accepted(string extension)
        {
            var dbName = Guid.NewGuid().ToString();
            using var context = GetDbContext(dbName);
            SeedDepartment(context);
            var dept = context.Departments.First();
            // Use a real writable path for file upload
            var testDir = Path.Combine(Directory.GetCurrentDirectory(), "test_uploads_" + Guid.NewGuid().ToString("N"));
            Directory.CreateDirectory(testDir);
            try
            {
                var controller = CreateController(context, testDir);
                var course = new Course
                {
                    CourseID = 4000 + extension.GetHashCode() % 1000,
                    Title = "Test",
                    Credits = 3,
                    DepartmentID = dept.DepartmentID
                };

                var fileMock = new Mock<IFormFile>();
                fileMock.Setup(f => f.FileName).Returns($"test{extension}");
                fileMock.Setup(f => f.Length).Returns(1024);
                fileMock.Setup(f => f.CopyTo(It.IsAny<Stream>()));

                var result = controller.Create(course, fileMock.Object) as RedirectToActionResult;

                Assert.IsNotNull(result);
                Assert.AreEqual("Index", result.ActionName);
            }
            finally
            {
                try { Directory.Delete(testDir, true); } catch { }
            }
        }

