        public void Setup()
        {
            _drainService = new NotificationService();
            while (_drainService.ReceiveNotification() != null) { }
        }

        [TestCleanup]
        public void Cleanup()
        {
            while (_drainService.ReceiveNotification() != null) { }
            _drainService.Dispose();
        }

        [TestMethod]
        public void GetNotifications_EmptyQueue_ReturnsSuccessWithEmptyList()
        {
            using var context = GetDbContext();
            var controller = new NotificationsController(context);

            var result = controller.GetNotifications();

            Assert.IsNotNull(result);
            Assert.IsInstanceOfType(result, typeof(JsonResult));
        }

        [TestMethod]
        public void GetNotifications_WithNotifications_ReturnsUpTo10()
        {
            using var context = GetDbContext();
            var notifService = new NotificationService();
            for (int i = 0; i < 15; i++)
            {
                notifService.SendNotification("Entity", i.ToString(), EntityOperation.CREATE);
            }

            var controller = new NotificationsController(context);
            var result = controller.GetNotifications();

            Assert.IsNotNull(result);
            // The result is a JsonResult with an anonymous type; we just verify it's returned
            Assert.IsInstanceOfType(result, typeof(JsonResult));
        }

        [TestMethod]
        public void MarkAsRead_ReturnsSuccess()
        {
            using var context = GetDbContext();
            var controller = new NotificationsController(context);

            var result = controller.MarkAsRead(1);

            Assert.IsNotNull(result);
            Assert.IsInstanceOfType(result, typeof(JsonResult));
        }

        [TestMethod]
        public void Index_ReturnsView()
        {
            using var context = GetDbContext();
            var controller = new NotificationsController(context);

            var result = controller.Index() as ViewResult;

            Assert.IsNotNull(result);
        }

        [TestMethod]
        public void GetNotifications_LimitsTo10()
        {
            using var context = GetDbContext();
            var notifService = new NotificationService();
            for (int i = 0; i < 20; i++)
            {
                notifService.SendNotification("Test", i.ToString(), EntityOperation.CREATE);
            }

            var controller = new NotificationsController(context);
            var result = controller.GetNotifications();

            // After getting 10, there should be remaining notifications
            // Send one more read to verify the queue still has items
            var remaining = notifService.ReceiveNotification();
            Assert.IsNotNull(remaining);
        }

        [TestMethod]
        public void MarkAsRead_WithAnyId_DoesNotThrow()
        {
            using var context = GetDbContext();
            var controller = new NotificationsController(context);

            // Should not throw for any ID
            var result1 = controller.MarkAsRead(0);
            var result2 = controller.MarkAsRead(-1);
            var result3 = controller.MarkAsRead(int.MaxValue);

            Assert.IsNotNull(result1);
            Assert.IsNotNull(result2);
            Assert.IsNotNull(result3);
        }
    }
}

